import { serializeJSON } from '@nordic/utils/serialize';

import { IS_VITE } from '../../utils/constants';
import { MANIFEST_ENTRYPOINTS_EXTENSIONS_REGEX } from '../regex';
import { readDiscoveryEntrypoints } from '../discovery';
import { createManifestEntries as createWebpackManifestEntries } from './webpack';
import { createManifestEntries as createViteManifestEntries } from './entries';

/* v8 ignore next -- Temp condition while webpack support is maintained */
const createManifestEntries = IS_VITE
  ? createViteManifestEntries
  : createWebpackManifestEntries;

function getSerializedManifest(manifestEntries: Array<[string, string]>) {
  if (__DEV__) {
    return serializeJSON(manifestEntries);
  }

  const discoveryEntrypoints = readDiscoveryEntrypoints();

  return serializeJSON(
    manifestEntries.filter(
      ([key, value]) =>
        MANIFEST_ENTRYPOINTS_EXTENSIONS_REGEX.test(value) &&
        !discoveryEntrypoints.has(
          key.replace(MANIFEST_ENTRYPOINTS_EXTENSIONS_REGEX, ''),
        ),
    ),
  );
}

export function createManifests() {
  const { baseManifestEntries, mainAssetsManifestEntries } =
    createManifestEntries();

  return {
    manifest: new Map(baseManifestEntries),
    mainAssetsManifest: new Map(mainAssetsManifestEntries),
    serializedManifest: getSerializedManifest(baseManifestEntries),
  };
}
